import { createContext, useContext, useState, useEffect } from 'react';
import { apiFetch } from '../lib/api';
import { useToast } from './ToastContext';

const AuthContext = createContext(null);

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const addToast = useToast();

  useEffect(() => {
    // TГџв•—в–’ в”ЂГ¦Гџв•—Г–ng nГџв•‘Г­p user tГџв•—ВЅ localStorage khi mГџв•—Вўi load
    try {
      const u = JSON.parse(localStorage.getItem('cb_user'));
      if (u && u.access_token) {
        setUser(u);
      }
    } catch (e) {
      console.error('Invalid user schema in storage.');
    }

    // LГџв•‘В»ng nghe window event khi token bГџв•—ГЇ 401
    const handleUnauthorized = () => {
      setUser(null);
      addToast('Phiв”њВ¬n lв”њГЎm viГџв•—Г§c hГџв•‘в”ђt hГџв•‘Г­n, vui lв”њв–“ng в”ЂГ¦в”ЂГўng nhГџв•‘ВЎp lГџв•‘Г­i.', 'err');
      window.location.href = '/customer-login';
    };

    window.addEventListener('auth:unauthorized', handleUnauthorized);
    return () => window.removeEventListener('auth:unauthorized', handleUnauthorized);
  }, [addToast]);

  const login = (userData) => {
    localStorage.setItem('cb_user', JSON.stringify(userData));
    setUser(userData);
    addToast(`Chв”њГЎo mГџв•—ВЅng ${userData.username || 'bГџв•‘Г­n'} trГџв•—Ж’ lГџв•‘Г­i!`, 'ok');
  };

  const logout = () => {
    localStorage.removeItem('cb_user');
    setUser(null);
    addToast('в”ЂГ‰в”ЂГўng xuГџв•‘Г‘t hoв”њГЎn tГџв•‘Г‘t.', 'info');
    window.location.href = '/';
  };

  const updateProfile = (newData) => {
    const updated = { ...user, ...newData };
    localStorage.setItem('cb_user', JSON.stringify(updated));
    setUser(updated);
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, updateProfile }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);

import { createContext, useContext, useState, useEffect, useCallback } from 'react';
import { apiFetch } from '../lib/api';
import { useAuth } from './AuthContext';

const CartContext = createContext(null);

export const CartProvider = ({ children }) => {
  const { user } = useAuth();
  const [cartCount, setCartCount] = useState(0);
  const [cartItems, setCartItems] = useState([]);

  // Fetch logic
  const fetchCart = useCallback(async () => {
    if (!user?.cart_id) {
       setCartCount(0);
       setCartItems([]);
       return;
    }

    try {
      // Proxy pattern tuГџв•—в”‚ service
      const res = await apiFetch(`/carts/${user.cart_id}/`);
      if (res.ok) {
        const data = await res.json();
        setCartItems(data.items || []);
        // TГџв•—ГІng sГџв•—Г¦ lв•ћв–‘Гџв•—Гєng item rГџв•—ВҐi rГџв•‘Г­c hay sГџв•—Г¦ loГџв•‘Г­i mГџв•‘в•–t hв”њГЎng? Dв”њв•Јng length
        setCartCount((data.items || []).length);
      }
    } catch (e) {
       console.error("LГџв•—Г№i lГџв•‘Г‘y giГџв•—Г… hв”њГЎng", e);
    }
  }, [user]);

  // Luв”њв”¤n bГџв•‘В»t trigger kв”њвЊђo giГџв•—Г… hв”њГЎng khi user thay в”ЂГ¦Гџв•—ГІi (VD log vв”њГЎo)
  useEffect(() => {
    fetchCart();
  }, [fetchCart]);

  return (
    <CartContext.Provider value={{ cartCount, cartItems, refreshCart: fetchCart }}>
      {children}
    </CartContext.Provider>
  );
};

export const useCart = () => useContext(CartContext);

import { createContext, useContext, useState, useCallback, ReactNode } from 'react';

const ToastContext = createContext(null);

export const ToastProvider = ({ children }) => {
  const [toasts, setToasts] = useState([]);

  const addToast = useCallback((msg, type = 'info') => {
    const id = Date.now() + Math.random().toString(36).substring(2, 9);
    setToasts((prev) => [...prev, { id, msg, type }]);

    // Auto-remove toast after 3 seconds
    setTimeout(() => {
      setToasts((prev) => prev.filter((t) => t.id !== id));
    }, 3000);
  }, []);

  return (
    <ToastContext.Provider value={addToast}>
      {children}
      <div className="toast-container">
        {toasts.map((t) => (
          <div key={t.id} className={`toast fade-in ${t.type === 'err' ? 'err' : t.type === 'ok' ? 'ok' : ''}`}>
            {t.msg}
          </div>
        ))}
      </div>
    </ToastContext.Provider>
  );
};

export const useToast = () => useContext(ToastContext);

import { useAuth } from '../context/AuthContext';
