      if(res.ok) {
        refreshCart();
      } else {
        addToast("Khв”њв”¤ng thГџв•—Гў cГџв•‘ВЎp nhГџв•‘ВЎt sГџв•—Г¦ lв•ћв–‘Гџв•—Гєng", "err");
