        <Link to="/customer-login" className="btn btn-primary">TГџв•—Вўi trang в”ЂГ‰в”ЂГўng NhГџв•‘ВЎp</Link>
      </div>
    );
  }

  return (
    <div className="container page-section">
      <h1 style={{ fontSize: '2.2rem', fontWeight: 800, marginBottom: '2.5rem', letterSpacing: '-0.02em' }}>GiГџв•—Г… hв”њГЎng cГџв•—Вєa bГџв•‘Г­n</h1>

      {cartItems.length === 0 ? (
        <div className="empty-state" style={{ background: 'var(--surface)', borderRadius: 'var(--radius-lg)', padding: '5rem 2rem', border: '1px dashed var(--border)' }}>
          <h3 style={{ fontSize: '1.4rem' }}>Chв•ћв–‘a cв”њв”‚ gв”њВј trong giГџв•—Г…</h3>
          <p style={{ marginBottom: '2rem' }}>Hв”њГєy tiГџв•‘в”ђp tГџв•—Г‘c mua sГџв•‘В»m vв”њГЎ lГџв•‘Г‘p в”ЂГ¦Гџв•‘Вєy giГџв•—Г… sв”њГ­ch yв”њВ¬u thв”њВЎch cГџв•—Вєa bГџв•‘Г­n.</p>
          <Link to="/" className="btn btn-primary btn-pill">BГџв•‘В»t в”ЂГ¦Гџв•‘Вєu mua sГџв•‘В»m</Link>
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 380px', gap: '3rem', alignItems: 'start' }}>
          <div>
            <div style={{ background: 'var(--surface)', borderRadius: 'var(--radius-lg)', padding: '1rem', border: '1px solid var(--border)' }}>
              {cartItems.map(item => (
                <div key={item.id} style={{ display: 'flex', gap: '1.5rem', padding: '1.5rem', borderBottom: '1px solid var(--surface-2)' }}>
                  <img src={item.image_url || 'https://via.placeholder.com/100x140'} alt={item.title} style={{ width: '100px', height: '140px', objectFit: 'cover', borderRadius: '8px', border: '1px solid var(--border)' }} />
