                    <div style={{ fontSize: '1.1rem', fontWeight: 700, marginBottom: '0.2rem' }}>{item.title}</div>
                    <div style={{ color: 'var(--text-4)', fontSize: '0.9rem', marginBottom: '1rem' }}>Mв”њГє Sв”њГ­ch: {item.id}</div>
                    <div style={{ fontSize: '1.2rem', fontWeight: 800, color: 'var(--primary)', marginTop: 'auto' }}>
                       {Number(item.price).toLocaleString()} О“Г©ВЅ
                    </div>
                  </div>
                  <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', justifyContent: 'space-between' }}>
                    <button onClick={() => removeItem(item.id, item.quantity)} style={{ background: 'none', border: 'none', color: 'var(--text-4)', cursor: 'pointer', padding: '0.5rem', borderRadius: '50%', transition: '0.2s', display: 'flex', alignItems: 'center', justifyContent: 'center' }} onMouseOver={e=>{e.currentTarget.style.color='var(--danger)'; e.currentTarget.style.background='var(--danger-light)'}} onMouseOut={e=>{e.currentTarget.style.color='var(--text-4)'; e.currentTarget.style.background='transparent'}}>
                      <Trash2 size={18} />
                    </button>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '1rem', border: '1px solid var(--border)', borderRadius: '30px', padding: '0.2rem 0.5rem' }}>
                       <button onClick={()=>updateQuantity(item.id, item.quantity - 1)} style={{ background: 'transparent', border:'none', fontSize: '1.2rem', cursor: 'pointer', padding: '0 0.5rem' }}>-</button>
                       <span style={{ fontWeight: 600, width: '20px', textAlign: 'center' }}>{item.quantity}</span>
                       <button onClick={()=>updateQuantity(item.id, item.quantity + 1)} style={{ background: 'transparent', border:'none', fontSize: '1.2rem', cursor: 'pointer', padding: '0 0.5rem' }}>+</button>
                    </div>
