              ))}
            </div>
          </div>

          <div style={{ background: 'var(--surface)', borderRadius: 'var(--radius-lg)', padding: '2rem', border: '1px solid var(--border)', position: 'sticky', top: '100px', boxShadow: 'var(--shadow-sm)' }}>
