import { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useCart } from '../context/CartContext';
import { useToast } from '../context/ToastContext';
import { apiFetch } from '../lib/api';
import BookCard from '../components/ui/BookCard';

export default function Home() {
  const { user } = useAuth();
  const { refreshCart } = useCart();
  const addToast = useToast();

  const [searchParams] = useSearchParams();
  const searchQ = searchParams.get('search') || '';

  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchBooks();
  }, [searchQ]);

  const fetchBooks = async () => {
    setLoading(true);
    try {
      let endpoint = `/books/`;
      if (searchQ) endpoint = `/books/search/?q=${encodeURIComponent(searchQ)}`;

      const res = await apiFetch(endpoint);
      if (res.ok) {
         const data = await res.json();
         // Handle pagination if needed, here we just take results
         setBooks(data.results || data.books || data || []);
      } else {
         addToast("Khв”њв”¤ng thГџв•—Гў tГџв•‘Гєi danh sв”њГ­ch sв”њГ­ch", "err");
      }
    } catch (e) {
      addToast("LГџв•—Г№i kГџв•‘в”ђt nГџв•—Г¦i", "err");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ flex: 1 }}>
      {!searchQ && (
        <div style={{ background: 'linear-gradient(135deg, var(--primary-light), var(--surface))', padding: '6rem 2rem', textAlign: 'center', position: 'relative', overflow: 'hidden' }}>
