            <h1 style={{ fontSize: '4.5rem', fontWeight: 900, marginBottom: '1.5rem', letterSpacing: '-0.04em', lineHeight: 1.1, color: 'var(--text-1)' }}>
              Tri thГџв•—вЊђc Khв”њв”¤ng giГџв•—Вўi hГџв•‘Г­n.<br/> <span style={{ color: 'var(--primary)' }}>CГџв•‘Гєm hГџв•—вЊђng BГџв•‘Г‘t tГџв•‘ВЎn.</span>
            </h1>
            <p style={{ color: 'var(--text-3)', fontSize: '1.25rem', maxWidth: '600px', margin: '0 auto 2.5rem', lineHeight: 1.6 }}>
              TuyГџв•—Гўn tГџв•‘ВЎp nhГџв•—В»ng tв”њГ­c phГџв•‘вЊђm khai phв”њв”‚ng tв•ћв–‘ duy. TrГџв•‘Гєi nghiГџв•—Г§m khв”њв”¤ng gian в”ЂГ¦Гџв•—Г¬c sв”њГ­ch tГџв•—Г¦i giГџв•‘Гєn, vв•ћв–‘Гџв•—Гєt giГџв•—Вўi hГџв•‘Г­n.
            </p>
            <button className="btn btn-primary btn-lg btn-pill" onClick={()=>window.scrollTo({top: window.innerHeight * 0.8, behavior:'smooth'})}>
              BГџв•‘В»t в”ЂГ¦Гџв•‘Вєu Khв”њГ­m phв”њГ­
            </button>
          </div>
          {/* Glass floating effects */}
          <div style={{ position: 'absolute', top: '10%', left: '20%', width: '300px', height: '300px', background: 'var(--secondary)', filter: 'blur(100px)', opacity: 0.15, borderRadius: '50%' }}></div>
          <div style={{ position: 'absolute', bottom: '10%', right: '20%', width: '400px', height: '400px', background: 'var(--primary)', filter: 'blur(120px)', opacity: 0.15, borderRadius: '50%' }}></div>
        </div>
      )}

      <div className="container page-section" style={{ padding: '4rem 2rem' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-end', marginBottom: '2.5rem' }}>
           <h2 style={{ fontSize: '1.8rem', fontWeight: 800, letterSpacing: '-0.02em', color: 'var(--text-1)' }}>
             {searchQ ? `KГџв•‘в”ђt quГџв•‘Гє tв”њВјm kiГџв•‘в”ђm cho "${searchQ}"` : 'Sв”њГ­ch NГџв•—ГІi BГџв•‘ВЎt MГџв•—Вўi NhГџв•‘Г‘t'}
           </h2>
        </div>

        {loading ? (
          <div style={{ textAlign: 'center', padding: '6rem' }}>
             <div className="spin spin-lg"></div>
          </div>
        ) : (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(260px, 1fr))', gap: '2rem' }}>
            {books.length > 0 ? books.map((b) => (
               <BookCard key={b.id} book={b} />
            )) : (
              <div className="empty-state" style={{ gridColumn: '1/-1' }}>
                <h3>Khв”њв”¤ng tв”њВјm thГџв•‘Г‘y cuГџв•—Г¦n sв”њГ­ch nв”њГЎo</h3>
                <p>ThГџв•—ВЎ sГџв•—ВЎ dГџв•—Г‘ng tГџв•—ВЅ khв”њв”‚a tiГџв•‘в”ђng anh hoГџв•‘в•–c kiГџв•—Гўm tra lГџв•‘Г­i tв”њВ¬n sв”њГ­ch.</p>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../context/ToastContext';
import { apiFetch } from '../lib/api';

export default function LoginCustomer() {
  const { login } = useAuth();
  const addToast = useToast();
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const isReg = searchParams.get('tab') === 'register';

  const [tab, setTab] = useState(isReg ? 'register' : 'login');
  const [loading, setLoading] = useState(false);
  const [form, setForm] = useState({ username: '', password: '', email: '' });

  const doAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const endpoint = tab === 'login' ? '/auth/login/' : '/auth/register/';
      const payload = { username: form.username, password: form.password };
      if (tab === 'register') {
        payload.email = form.email;
        payload.role = 'customer';
      }

      const r = await apiFetch(endpoint, {
        method: 'POST', 
        body: JSON.stringify(payload)
      });

      const d = await r.json();

      if(r.ok && d.access_token) {
        if(d.user?.role !== 'customer') {
          addToast('Tв”њГЎi khoГџв•‘Гєn nГџв•—Г–i bГџв•—Г–. Vui lв”њв–“ng в”ЂГ¦в”ЂГўng nhГџв•‘ВЎp qua Internal Portal.', 'err');
          return;
        }
        login({
          access_token: d.access_token,
          username: d.user.username,
          service_user_id: d.user.service_user_id,
          cart_id: d.user.cart_id,
          role: d.user.role
        });
        setTimeout(() => navigate('/'), 800);
      } else {
